function matrixBlockSum(mat, k) {
    const m = mat.length;
    const n = mat[0].length;
    const answer = new Array(m).fill(null).map(() => new Array(n).fill(0));

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            for (let r = Math.max(0, i - k); r <= Math.min(m - 1, i + k); r++) {
                for (let c = Math.max(0, j - k); c <= Math.min(n - 1, j + k); c++) {
                    answer[i][j] += mat[r][c];
                }
            }
        }
    }

    return answer;
}
